section.code:
{
  "$schema": "https://json-schema.org/draft/2020-12/schema",
  "$id": "https://faion.net/schemas/go-http-handlers",
  "type": "object",
  "required": ["server", "handlerShape"],
  "properties": {
    "server": {
      "type": "object",
      "required": ["framework", "middlewareOrder", "timeouts", "shutdown"],
      "properties": {
        "framework": {"enum": ["gin", "echo", "net-http"]},
        "middlewareOrder": {
          "type": "array",
          "items": {"type": "string"},
          "contains": {"const": "Recovery"},
          "description": "Recovery first; Logger second; RequestID third; auth + domain after."
        },
        "timeouts": {
          "type": "object",
          "required": ["readHeader", "read", "write", "idle"],
          "properties": {
            "readHeader": {"type": "integer", "minimum": 1},
            "read":       {"type": "integer", "minimum": 1},
            "write":      {"type": "integer", "minimum": 1},
            "idle":       {"type": "integer", "minimum": 1}
          }
        },
        "shutdown": {
          "type": "object",
          "required": ["signal", "drainSeconds"],
          "properties": {
            "signal": {"enum": ["SIGINT,SIGTERM"]},
            "drainSeconds": {"type": "integer", "minimum": 5, "maximum": 60}
          }
        }
      }
    },
    "handlerShape": {
      "type": "object",
      "required": ["maxLines", "allowedSteps"],
      "properties": {
        "maxLines": {"type": "integer", "maximum": 40},
        "allowedSteps": {
          "type": "array",
          "items": {"enum": ["bind", "validate-binding", "call-service", "translate-to-http"]}
        }
      }
    }
  }
}

example.code:
func Wire(cfg *Config, deps *Deps) *http.Server {
    r := gin.New()                         // r2
    r.Use(mw.Recovery())                   // r1: Recovery first
    r.Use(mw.RequestID())
    r.Use(mw.Logger(deps.Log))
    r.Use(mw.Auth(deps.JWT))
    r.POST("/users", deps.UserHandler.Create)
    return &http.Server{
        Addr:              cfg.Addr,
        Handler:           r,
        ReadHeaderTimeout: 5 * time.Second,    // r8
        ReadTimeout:       30 * time.Second,
        WriteTimeout:      30 * time.Second,
        IdleTimeout:       120 * time.Second,
    }
}

func (h *UserHandler) Create(c *gin.Context) {
    var req CreateUserRequest
    if err := c.ShouldBindJSON(&req); err != nil {        // r7
        _ = c.Error(err); return
    }
    u, err := h.svc.Create(c.Request.Context(), req.ToDomain())  // r3
    if err != nil { _ = c.Error(err); return }
    c.JSON(201, u)
}

func main() {
    r := gin.Default()                     // r2 violated
    r.POST("/users", func(c *gin.Context) {
        var u model.User
        c.BindJSON(&u)
        ctx := context.Background()         // r4 violated
        go func() { svc.Notify(c) }()       // r5 violated
        if u.Email == "" { /* ... */ }      // r6/r7 violated
        c.JSON(200, svc.CreateUser(ctx, &u))
    })
    r.Run(":8080")                          // no timeouts (r8 violated)
}
